/// Cross-reference verification: Dart SDK output vs TypeScript Anchor SDK truth values.
///
/// This test loads `test/reference/references.json` (generated by the TS Anchor SDK)
/// and verifies that the Dart SDK computes identical:
///   - Instruction discriminators (SHA256 of "global:" + snake_case_name)
///   - Account discriminators (SHA256 of "account:" + name)
///   - Event discriminators (SHA256 of "event:" + name)
///   - Encoded instruction bytes (discriminator + Borsh-serialized args)
///   - Standalone discriminator computations
///   - Borsh primitive encoding (u8, u16, u32, u64, i8, i16, i32, i64, bool, string)
///
/// This is the ground-truth test: if the Dart SDK produces different bytes than
/// the TypeScript SDK for the same inputs, the Dart SDK is wrong.
library;

import 'dart:convert';
import 'dart:io';
import 'dart:typed_data';

import 'package:coral_xyz/src/coder/borsh_types.dart';
import 'package:coral_xyz/src/coder/discriminator_computer.dart';
import 'package:coral_xyz/src/coder/instruction_coder.dart';
import 'package:coral_xyz/src/idl/idl.dart';
import 'package:test/test.dart';

import 'verification_helpers.dart';

/// Load the TS-generated reference JSON.
Map<String, dynamic> _loadReferences() {
  final file = File('test/reference/references.json');
  return jsonDecode(file.readAsStringSync()) as Map<String, dynamic>;
}

/// Load an IDL from the reference test fixtures.
Idl _loadReferenceIdl(String programName) {
  // Map program names to their IDL filenames
  const idlFiles = {
    'basic_counter': 'basic_counter_idl.json',
    'clever_todo': 'todo_idl.json',
    'flutter_vote': 'voting_idl.json',
  };
  final filename = idlFiles[programName];
  if (filename == null) {
    throw StateError('No IDL file mapping for program: $programName');
  }
  final file = File('test/reference/$filename');
  final json = jsonDecode(file.readAsStringSync()) as Map<String, dynamic>;
  return Idl.fromJson(json);
}

/// Convert a JSON list of ints to Uint8List.
Uint8List _jsonBytesToUint8List(List<dynamic> jsonBytes) {
  return Uint8List.fromList(jsonBytes.cast<int>());
}

void main() {
  late Map<String, dynamic> refs;
  late VerificationReport report;

  setUpAll(() {
    refs = _loadReferences();
    report = VerificationReport();
  });

  tearDownAll(() {
    report.printSummary();
  });

  // ===========================================================================
  // Section 1: Per-program discriminator verification
  // ===========================================================================
  group('Per-program instruction discriminators match TS', () {
    test('basic_counter instructions', () {
      final programRefs =
          refs['programs']['basic_counter'] as Map<String, dynamic>;
      final ixRefs = programRefs['instructions'] as Map<String, dynamic>;

      for (final entry in ixRefs.entries) {
        final ixName = entry.key;
        final ixData = entry.value as Map<String, dynamic>;
        final expectedBytes = _jsonBytesToUint8List(
          ixData['discriminator'] as List,
        );
        final preimage = ixData['preimage'] as String;

        // Dart SDK computes discriminator from the preimage prefix + snake_case name
        // The preimage is "global:snake_case_name"
        final dartDiscriminator =
            DiscriminatorComputer.computeInstructionDiscriminator(
              preimage.replaceFirst('global:', ''),
            );

        expect(
          dartDiscriminator,
          equals(expectedBytes),
          reason:
              'Instruction "$ixName" discriminator mismatch. '
              'Preimage: $preimage',
        );
        report.pass(
          'Anchor',
          'basic_counter.$ixName discriminator',
          detail: 'matches TS: ${ixData["discriminatorHex"]}',
        );
      }
    });

