// =============================================================================
// Helpers
// =============================================================================

/// Convert args from JSON representation to what the Dart encoder expects.
///
/// Key conversions:
/// - u64 string values → BigInt (JSON can't represent u64 precisely)
/// - u8 values stay as int
Map<String, dynamic> _convertArgsForEncoding(
  Map<String, dynamic> args,
  Idl idl,
  String ixName,
) {
  if (args.isEmpty) return args;

  // Find the instruction definition to know field types
  final ixDef = idl.instructions.firstWhere(
    (ix) => ix.name == ixName,
    orElse: () => throw StateError('Instruction $ixName not found in IDL'),
  );

  final converted = <String, dynamic>{};
  for (final entry in args.entries) {
    final argName = entry.key;
    final argValue = entry.value;

    // Find the type definition for this arg
    final argDef = ixDef.args.firstWhere(
      (a) => a.name == argName,
      orElse: () =>
          throw StateError('Arg $argName not found in instruction $ixName'),
    );

    final type = argDef.type;
    final typeStr = type.kind;

    if ((typeStr == 'u64' || typeStr == 'i64') && argValue is String) {
      // JSON-encoded large numbers come as strings
      converted[argName] = BigInt.parse(argValue);
    } else if ((typeStr == 'u64' || typeStr == 'i64') && argValue is int) {
      converted[argName] = BigInt.from(argValue);
    } else {
      converted[argName] = argValue;
    }
  }
  return converted;
}

/// Resolve an IDL type object to a simple string for type checking.
String _resolveTypeString(dynamic type) {
  if (type is String) return type;
  if (type is Map<String, dynamic>) {
    if (type.containsKey('vec')) return 'vec';
    if (type.containsKey('option')) return 'option';
    if (type.containsKey('array')) return 'array';
    if (type.containsKey('defined')) return 'defined';
  }
  return 'unknown';
}

/// Encode a single Borsh primitive value for verification against TS.
///
/// Uses the BorshSerializer from the instruction coder since that's what
/// the SDK uses to encode real instruction data.
Uint8List _encodePrimitive(String type, dynamic value) {
  final serializer = BorshSerializer();

  switch (type) {
    case 'u8':
      serializer.writeU8(value as int);
    case 'u16':
      serializer.writeU16(value as int);
    case 'u32':
      serializer.writeU32(value as int);
    case 'u64':
      final bigVal = value is String
          ? BigInt.parse(value)
          : BigInt.from(value as int);
      serializer.writeU64(bigVal);
    case 'i8':
      serializer.writeI8(value as int);
    case 'i16':
      serializer.writeI16(value as int);
    case 'i32':
      serializer.writeI32(value as int);
    case 'i64':
      final intVal = value is String ? int.parse(value) : value as int;
      serializer.writeI64(intVal);
    case 'bool':
      serializer.writeBool(value as bool);
    case 'string':
      serializer.writeString(value as String);
    default:
      throw ArgumentError('Unsupported primitive type: $type');
  }

  return serializer.toBytes();
}
